Rule.Source:
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Global-Company-Rule");

  logger.debug("Start Ascension-Global-Company-Rule");

  String attributeValue = null;
  String ministryVal = "";
  HashMap companies = new HashMap();

  IdentityService idService = new IdentityService(context);


  if(null != identity){	
    
    List<Link> appLinks = null;
    Application app = context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");		

    if(null != app && !Util.isEmpty((appLinks = idService.getLinks( identity, app)))){	
      if( null != appLinks && appLinks.get(0) != null){
        String businessUnit = appLinks.get(0).getAttribute("BUSINESS_UNIT");
        if(Util.isNotNullOrEmpty(businessUnit)){
          Custom customBU = context.getObject(Custom.class, "Ascension-Custom-BU-Mappings");
          if(customBU!=null){
            String company = customBU.get(businessUnit);

            if(Util.isNotNullOrEmpty(company)){
              attributeValue = company;
            }
            //comment decache //context.decache(customBU);
          }
        }
      }
    }

    ministryVal = identity.getStringAttribute("ministry");    
    if(Util.isNullOrEmpty(attributeValue) && Util.isNotNullOrEmpty(ministryVal)){
      Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");

      if(custom != null ){
        if( custom.get("IdentityCompanyMapping") !=null){
          companies = custom.get("IdentityCompanyMapping");
        }
        //comment decache //context.decache(custom);
      }

      if(  !Util.isEmpty(companies) && companies.get(ministryVal) instanceof String){
        attributeValue = companies.get(ministryVal);         
      }
    }
    
    if(Util.isNullOrEmpty(attributeValue)){
    	attributeValue = identity.getStringAttribute("company");
    }

    if(null != app){
      //comment decache //context.decache(app);
    }
  }

  logger.debug("End Ascension-Global-Ministry-Rule");  
  return attributeValue;
